{
  "mode": "method",
  "tests": [
    {
      "name": "fetch_scorecard_details_success",
      "input": {
        "challengeId": "12345"
      },
      "output": {
        "scorecard": {
          "id": "1",
          "challengeId": "12345",
          "reviewerId": "67890",
          "score": 85,
          "comments": "Well done!"
        }
      },
      "args": [],
      "kwargs": {},
      "notes": "Validates successful fetching of scorecard details from the Review API."
    },
    {
      "name": "fetch_scorecard_details_not_found",
      "input": {
        "challengeId": "99999"
      },
      "output": {
        "error": "Scorecard not found"
      },
      "args": [],
      "kwargs": {},
      "notes": "Tests handling of a non-existent scorecard."
    },
    {
      "name": "create_appeal_success",
      "input": {
        "scorecardId": "1",
        "appeal": {
          "reason": "Need clarification on scoring",
          "details": "The score seems lower than expected."
        }
      },
      "output": {
        "appealId": "1001",
        "status": "created"
      },
      "args": [],
      "kwargs": {},
      "notes": "Validates successful creation of an appeal."
    },
    {
      "name": "create_appeal_invalid_data",
      "input": {
        "scorecardId": "1",
        "appeal": {
          "reason": "",
          "details": ""
        }
      },
      "output": {
        "error": "Invalid appeal data"
      },
      "args": [],
      "kwargs": {},
      "notes": "Tests validation of appeal creation with empty fields."
    },
    {
      "name": "update_appeal_success",
      "input": {
        "appealId": "1001",
        "update": {
          "details": "Requesting further clarification on scoring."
        }
      },
      "output": {
        "status": "updated"
      },
      "args": [],
      "kwargs": {},
      "notes": "Validates successful update of an existing appeal."
    },
    {
      "name": "delete_appeal_success",
      "input": {
        "appealId": "1001"
      },
      "output": {
        "status": "deleted"
      },
      "args": [],
      "kwargs": {},
      "notes": "Validates successful deletion of an appeal."
    },
    {
      "name": "role_based_access_reviewer",
      "input": {
        "userRole": "Reviewer",
        "action": "view"
      },
      "output": {
        "allowed": true
      },
      "args": [],
      "kwargs": {},
      "notes": "Tests role-based access control for a Reviewer."
    },
    {
      "name": "role_based_access_submitter",
      "input": {
        "userRole": "Submitter",
        "action": "edit"
      },
      "output": {
        "allowed": false
      },
      "args": [],
      "kwargs": {},
      "notes": "Tests role-based access control for a Submitter trying to edit."
    }
  ],
  "assumptions": "All API endpoints are functional and accessible.",
  "notes": "Ensure to handle loading and error states appropriately in the UI."
}
